1	export type Item = {
2	  kind: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
3	  cursed?: boolean;
4	  enchantment?: number;
5	};
6	
7	export type QuoteStep = { kind: "quote"; items: Item[] };
8	
9	export type Scenario = {
10	  customer: { yearsWithMHPCO: number };
11	  steps: QuoteStep[];
12	};
13	
14	export type ScenarioResult = {
15	  results: unknown[];
16	};
17	
18	const COMPONENT_BASE_PREMIUM = 25;
19	
20	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: COMPONENT_BASE_PREMIUM,
26	  moonstone: COMPONENT_BASE_PREMIUM,
27	};
28	
29	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
30	const PER_CONTRACT_DISCOUNT_RATE = 0.15;
31	const LOYALTY_DISCOUNT_RATE = 0.2;
32	const LOYALTY_THRESHOLD_YEARS = 2;
33	const PROCESSING_FEE = 5;
34	
35	const CURSED_SURCHARGE_RATE = 0.5;
36	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	
39	function isCursed(item: Item): boolean {
40	  return item.cursed === true;
41	}
42	
43	function isHighlyEnchanted(item: Item): boolean {
44	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
45	}
46	
47	function riskMultiplierForItem(item: Item): number {
48	  return (
49	    1 +
50	    (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
51	    (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0)
52	  );
53	}
54	
55	function basePremiumForItem(item: Item): number {
56	  return BASE_PREMIUM_BY_ITEM[item.kind] * riskMultiplierForItem(item);
57	}
58	
59	type QuoteResult = { kind: "quote"; premium: number };
60	
61	const BUILDING_BLOCK_BASE_PREMIUM = 60;
62	const BUILDING_BLOCK_SIZE = 3;
63	const COMPONENT_KINDS: ReadonlyArray<Item["kind"]> = ["rune", "moonstone"];
64	
65	type ItemGroup = { kind: Item["kind"]; items: Item[] };
66	
67	function groupByKind(items: Item[]): ItemGroup[] {
68	  const groups = new Map<Item["kind"], Item[]>();
69	  for (const item of items) {
70	    const group = groups.get(item.kind) ?? [];
71	    group.push(item);
72	    groups.set(item.kind, group);
73	  }
74	  return Array.from(groups, ([kind, items]) => ({ kind, items }));
75	}
76	
77	function isBuildingBlock(group: ItemGroup): boolean {
78	  return group.items.length === BUILDING_BLOCK_SIZE && COMPONENT_KINDS.includes(group.kind);
79	}
80	
81	function basePremiumForGroup(group: ItemGroup): number {
82	  if (isBuildingBlock(group)) {
83	    return BUILDING_BLOCK_BASE_PREMIUM;
84	  }
85	  return group.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
86	}
87	
88	function basePremiumForItems(items: Item[]): number {
89	  return groupByKind(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
90	}
91	
92	function contractSequenceRate(contractIndex: number): number {
93	  return contractIndex === 0 ? FIRST_INSURANCE_SURCHARGE_RATE : -PER_CONTRACT_DISCOUNT_RATE;
94	}
95	
96	function loyaltyRate(customer: Scenario["customer"]): number {
97	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? -LOYALTY_DISCOUNT_RATE : 0;
98	}
99	
100	function customerRateForContract(
101	  contractIndex: number,
102	  customer: Scenario["customer"],
103	): number {
104	  return contractSequenceRate(contractIndex) + loyaltyRate(customer);
105	}
106	
107	function quoteStep(
108	  step: QuoteStep,
109	  contractIndex: number,
110	  customer: Scenario["customer"],
111	): QuoteResult {
112	  const basePremium = basePremiumForItems(step.items);
113	  const customerAdjustment = basePremium * customerRateForContract(contractIndex, customer);
114	  const premium = Math.ceil(basePremium + customerAdjustment + PROCESSING_FEE);
115	  return { kind: "quote", premium };
116	}
117	
118	export function processScenario(scenario: Scenario): ScenarioResult {
119	  const results = scenario.steps.map((step, index) => quoteStep(step, index, scenario.customer));
120	  return { results };
121	}
